var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"문이 잠겨 있네요.","JPN":"ドアにカギがかかっていますね。","ENG":"The door seems to be locked.","TWN":"門鎖起來了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"잠시 기다리세요. 열쇠를 가져오겠습니다.","JPN":"少々お待ちください。カギをお持ちします。","ENG":"Hold on. I'll go get the keys.","TWN":"請稍候，我去拿鑰匙。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시, 시니어님……?","JPN":"し、シニア……？","ENG":"S-sir...?","TWN":"Senior……？"},"stage":{"bg":"CHARADE2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"머리가…… 사라졌어? 이, 이게 대체 무슨……?","JPN":"頭部が……消えている？　こ、これはいったいどういう……？","ENG":"Where's... his head? W-what's happened to him...?","TWN":"頭……不見了？怎，怎麼會這樣……？"},"stage":{"bg":"CHARADE2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님, 이건…….","JPN":"社長、これって……","ENG":"Boss, this looks like...","TWN":"老闆，這是……"},"stage":{"bg":"CHARADE2_03","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CHARADE2_03","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직원들에게 연락해 주게나, 미나 양.","JPN":"社員たちに連絡してくれ、ミナ君。","ENG":"Mina, go call our employees.","TWN":"米娜，幫我聯絡大家。"},"stage":{"bg":"CHARADE2_03","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 좀 바빠질 것 같군.","JPN":"どうやら忙しくなりそうだ。","ENG":"It looks like we'll be busy soon.","TWN":"看來之後會有點忙。"},"stage":{"bg":"CHARADE2_03","slots":{"L":null,"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"한 시간 뒤","JPN":"1時間後","ENG":"1 hour later","TWN":"一小時後","DEU":"1 hour later","FRA":"1 hour later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 대장님.","JPN":"はい、隊長。","ENG":"Yes, Commander.","TWN":"你好，隊長。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Oh?","TWN":"咦？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당연히 안 받을 줄 알았는데, 의외의 반응이네요.","JPN":"絶対に出ないと思ってたのに、意外ですね。","ENG":"I didn't think you'd pick up. This is unexpected.","TWN":"我還以為你肯定不會接呢，真出乎意料。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뻔뻔하게 전화를 거셨으니, 저도 뻔뻔하게 받은 것뿐인 걸요.","JPN":"図々しく電話をかけてきましたので、私も図々しく出ただけです。","ENG":"Well, you were shameless enough to call, so I am being shameless and picking up.","TWN":"你厚著臉皮打了電話，我就厚著臉皮接了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저와 무슨 대화가 하고 싶은 거죠?","JPN":"なにか私に用件ですか？","ENG":"What did you want to talk about?","TWN":"你想和我談什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아주 요란스럽게 일을 벌이고 떠났더군요.","JPN":"また盛大にやってくれましたね。","ENG":"You really stirred things up before you left.","TWN":"我看你惹出了不少麻煩呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"샤레이드의 시니어를 그런 식으로 처리할 줄은 몰랐어요.","JPN":"シャレードのシニアをあんなふうに処理するとは思いませんでした。","ENG":"I never expected you to take care of Charade's Senior in that manner.","TWN":"沒想到會以那種方式處理查雷德的Senior。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 누군가 제 뒤를 캐는 걸 별로 좋아하지 않거든요.","JPN":"私は誰かに調査されるのが、好きではありませんので。","ENG":"I'm not a fan of people prying on me.","TWN":"因為我不喜歡有人在背後摸我底細。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신을 따르는 그 새침데기 리트리버도 마찬가지고요.","JPN":"あなたに従うあのすましたレトリーバーもそうです。","ENG":"Including that coy little retriever of yours.","TWN":"你那隻裝模作樣的獵犬也一樣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제법 감정적이시네요. 저희가 스완 씨의 심기를 제대로 거슬렀나 봐요.","JPN":"思ったより感情的なんですね。僕たちがスワンさんの機嫌を損ねてしまったようです。","ENG":"You're quite emotional. We must've upset you deeply.","TWN":"你似乎很激動，我們是不是惹你生氣了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 예정된 전개예요. 제 감정은 한 번도 각본을 벗어난 적이 없습니다.","JPN":"すべて予想された展開でした。私の感情は一度も脚本から外れたことはありません。","ENG":"Everything is according to plan. My emotions have never strayed from the script.","TWN":"一切都是事先安排好的。我的情緒從來沒有脫離過劇本。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만, 그 대답을 듣고도 잘 이해가 안 되는 부분이 있어요.","JPN":"そうでしょうか？　でも、気になるところがあります。","ENG":"But that answer is still not enough to help me understand this one thing.","TWN":"不過，我對這個答案還是有些不太理解。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신은 분명 그날 최고관리자님의 정체를 알아봤을 텐데요.","JPN":"あなたは確かにあの日、最高管理者さんの正体を知ったはずです。","ENG":"I'm sure you recognized the Supreme Administrator's identity that day.","TWN":"你那天一定認出了最高管理者的真實身分。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리자님을 노리는 건, 보안을 뚫고 그 시니어를 처리하는 것보다 쉬운 일이었겠죠. 그렇지 않나요?","JPN":"管理者さんを狙うのは、保安を突破してあのシニアを処理することより簡単だった。違いますか？","ENG":"Going for the Administrator would've been easier than going through all that security to eliminate the Senior, am I wrong?","TWN":"與其突破保全處理Senior，直接對管理者下手應該更容易不是嗎？"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후훗, 모든 걸 알고 있는 양 말하던 당신도… 지금은 호기심 많은 아이일 뿐이군요.","JPN":"ふふっ、すべてを知っているかのように話していたあなたも……今では好奇心旺盛な子ども同然ですね。","ENG":"Fu fuu, you used to act like you knew everything... and now you're just another child, full of curiosity.","TWN":"呵呵，你雖然一副什麼都知道的語氣……但其實你也是一個充滿好奇心的孩子而已。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 원하지 않았다. 그 정도 설명으론 부족할까요?","JPN":"私がそれを望んでいなかった。この説明で納得していただけるでしょうか？","ENG":"I didn't want to. Is that enough of a reason for you?","TWN":"我並不想這麼做。這個理由充分嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신이 그토록 찾았고, 당신의 각본에 걸림돌이 될 게 뻔한 존재일 텐데요?","JPN":"あなたがあんなにも探し求め、恐らくあなたの脚本の邪魔になる存在なのにですか？","ENG":"You were looking for him so hard, and he's sure to be an obstacle in your play.","TWN":"那是你一直在追尋的，會成為你的劇本當中的絆腳石的人。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"괜찮아요.","JPN":"ええ。","ENG":"It's fine.","TWN":"無所謂。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전 오히려 그 사람이 살아서 봐줬으면 하거든요.","JPN":"私はむしろ、あの人に生きて見届けてもらいたいのです。","ENG":"I'd prefer him to survive and watch.","TWN":"我寧願他活著看到這一切。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 곧 이뤄내게 될 일들을.","JPN":"もうすぐ私が成し遂げることを。","ENG":"Watch the things I'm about to accomplish.","TWN":"看到我將實現的一切目標。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"대장, 아까부터 뭘 그렇게 골몰히 생각하시죠?","JPN":"隊長、先程から何をそんなに考え込んでいるのですか？","ENG":"Commander, you've been deep in thought for a while now.","TWN":"隊長，您從剛剛開始就在想什麼呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"역시 그 여자에 관한 건가요?","JPN":"やはりあの女のことですか。","ENG":"Is it about that woman, again?","TWN":"果然是在想那個女人的事嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네, 아무래도 위화감이 느껴져서요.","JPN":"はい、どうしても違和感があって。","ENG":"Yes. I can't shake this sense of unease.","TWN":"嗯，總覺得有種違和感。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"L12_1"},"R":null}}}]`);export{e as default};